import colorama
from colorama import Fore, Style

class Board:
    def __init__(self):
        self.board = [[' ' for _ in range(8)] for _ in range(8)]
        self.init_board()

    def init_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = 'B'
        for i in range(5, 8):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = 'W'

    def print_board(self):
        colorama.init()
        for i in range(8):
            if i % 2 == 0:
                print(' ', end='')
            else:
                print('', end='')
            for j in range(8):
                piece = self.board[i][j]
                if piece == 'B':
                    print(Fore.BLUE + 'BP' + Style.RESET_ALL, end=' ')
                elif piece == 'W':
                    print(Fore.RED + 'WP' + Style.RESET_ALL, end=' ')
                elif piece == 'BK':
                    print(Fore.BLUE + 'BKP' + Style.RESET_ALL, end=' ')
                elif piece == 'WK':
                    print(Fore.RED + 'WKP' + Style.RESET_ALL, end=' ')
                else:
                    print('..', end=' ')
            print()
        colorama.deinit()

    def move_piece(self, from_pos, to_pos):
        x1, y1 = from_pos
        x2, y2 = to_pos
        piece = self.board[x1][y1]
        if abs(x2 - x1) == 2 and abs(y2 - y1) == 2:
            # Capture move
            mid_x = (x1 + x2) // 2
            mid_y = (y1 + y2) // 2
            self.board[mid_x][mid_y] = ' '
        self.board[x1][y1] = ' '
        self.board[x2][y2] = piece

    def is_valid_move(self, from_pos, to_pos):
        x1, y1 = from_pos
        x2, y2 = to_pos
        if abs(x2 - x1) != 1 or abs(y2 - y1) not in (1, 2):
            return False
        piece = self.board[x1][y1]
        if piece == ' ':
            return False
        if (piece.islower() and x2 > x1) or (piece.isupper() and x2 < x1):
            return False
        if abs(x2 - x1) == 2 and abs(y2 - y1) == 2:
            # Check for valid capture move
            mid_x = (x1 + x2) // 2
            mid_y = (y1 + y2) // 2
            if self.board[mid_x][mid_y] == ' ':
                return False
        return True

    def king_piece(self, pos):
        x, y = pos
        piece = self.board[x][y]
        if (x == 0 and piece.islower()) or (x == 7 and piece.isupper()):
            self.board[x][y] = piece.upper()
```

#### 3.2. Game Class
Next, we'll create a class to manage the game state.

**game.py**

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'W'

    def print_board(self):
        self.board.print_board()

    def switch_player(self):
        self.current_player = 'B' if self.current_player == 'W' else 'W'

    def get_user_input(self):
        move = input(f"Player {self.current_player}, enter your move (from-to): ")
        from_pos, to_pos = map(int, move.split('-'))
        return (from_pos // 10, from_pos % 10), (to_pos // 10, to_pos % 10)

    def make_move(self):
        from_pos, to_pos = self.get_user_input()
        if not self.board.is_valid_move(from_pos, to_pos):
            print("Invalid move. Please try again.")
            return
        self.board.move_piece(from_pos, to_pos)
        if abs(to_pos[1] - from_pos[1]) == 2:
            # King piece after capture
            self.board.king_piece(to_pos)
        self.switch_player()

    def play(self):
        while True:
            self.print_board()
            self.make_move()
            # Check for win/draw conditions (not implemented yet)
```

